    },
    onYolo: (setTo?: boolean) => {
      const policy = container.resolve(TOKENS.PermissionPolicy) as DefaultPermissionPolicy;
      if (setTo !== undefined) {
        policy.setYolo(setTo);
        config = patchConfig(config, { yolo: setTo });
